      interview: [
        { level: "Junior", q: "What is React Router?", a: "A library for routing in React web applications, allowing navigation between components without page reloads.", type: "Conceptual" },
        { level: "Junior", q: "Difference between Link and <a> tag?", a: "<Link> prevents a full page reload and instead updates the component tree using the history API.", type: "Conceptual" },
        { level: "Junior", q: "How do you create a 404 page?", a: "By adding a <Route path='*' element={<NotFound />} /> at the end of your routes list.", type: "Coding" },
        { level: "Junior", q: "What is the BrowserRouter?", a: "A router implementation that uses the HTML5 history API (pushState, replaceState and the popstate event) to keep your UI in sync with the URL.", type: "Conceptual" },
        { level: "Junior", q: "How do you define routes in React Router?", a: "By wrapping <Route> elements inside a <Routes> component, specifying path and element props for each.", type: "Coding" },
        { level: "Junior", q: "What is its .to prop used for in the Link component?", a: "It specifies the path or location where the link should navigate to.", type: "Conceptual" },
        { level: "Junior", q: "What is the purpose of NavLink?", a: "It's a special version of Link that will add styling attributes to the rendered element when it matches the current URL.", type: "Conceptual" },
        { level: "Junior", q: "How do you get dynamic data from the URL?", a: "Using the useParams() hook to access the parameters defined in the route path (e.g., :id).", type: "Coding" },
        { level: "Junior", q: "What is the Navigate component?", a: "A component that triggers a redirect to a new location when it is rendered.", type: "Conceptual" },
        { level: "Junior", q: "How do you make a link open in a new tab?", a: "By adding the target='_blank' attribute to the <Link> component.", type: "Conceptual" },
        { level: "Junior", q: "What is the role of the Routes component?", a: "It looks through all its children <Route> elements and finds the one that best matches the current location.", type: "Conceptual" },
        { level: "Junior", q: "Can you use React Router without a backend?", a: "Yes, it's designed for SPAs where the browser navigation is handled strictly on the frontend.", type: "Scenario" },
        { level: "Junior", q: "What is a 'Path' in React Router?", a: "A string pattern that represents the URL fragment where a component should be displayed.", type: "Conceptual" },
        { level: "Mid", q: "How do you handle dynamic parameters?", a: "By using the ':' syntax in the route path (e.g., /user/:id) and the useParams() hook in the component.", type: "Conceptual" },
        { level: "Mid", q: "Explain the useNavigate hook.", a: "It returns a function that allows you to programmatically navigate the user to different routes (e.g., after a login).", type: "Conceptual" },
        { level: "Mid", q: "What is an <Outlet />?", a: "A component that should be used in parent route elements to render their child route elements.", type: "Conceptual" },
        { level: "Mid", q: "Explain the difference between useParams and useSearchParams.", a: "useParams is for dynamic segments in the URL path. useSearchParams is for query parameters (?key=value).", type: "Conceptual" },
        { level: "Mid", q: "What is 'Nested Routing' and why use it?", a: "The concept of keeping part of the URL stable while swapping out inner components, typically for dashboard layouts.", type: "Conceptual" },
        { level: "Mid", q: "Explain how to pass 'State' during navigation.", a: "By using the state prop in navigate() or <Link />, which can be accessed via useLocation().state.", type: "Coding" },
        { level: "Mid", q: "What is an 'Index Route'?", a: "A child route with no path that renders when the parent's path is matched exactly.", type: "Conceptual" },
        { level: "Mid", q: "Explain 'basename' prop utility.", a: "It provides a base URL for all locations in the app, useful for apps hosted in a subfolder.", type: "Conceptual" },
        { level: "Mid", q: "How do you manage scroll position on navigation?", a: "Using the ScrollRestoration component or a custom useEffect on location change to scroll(0,0).", type: "Scenario" },
        { level: "Mid", q: "What is useLocation hook useful for?", a: "Reading current path, query strings, and custom state passed from previous routes.", type: "Conceptual" },
        { level: "Mid", q: "How do you define 'Catch-all' routes?", a: "Using the '*' path which matches any URL not explicitly matched by other routes.", type: "Coding" },
        { level: "Mid", q: "Explain useRoutes hook.", a: "A functional equivalent to the <Routes> component that allows defining routes as a JavaScript object.", type: "Conceptual" },
        { level: "Senior", q: "How do you implement a 'Protected Route'?", a: "By creating a wrapper component that checks for an authentication token; if exists, it renders the <Outlet />, otherwise it redirects to /login.", type: "Scenario" },
        { level: "Senior", q: "What is 'Code Splitting' with React Router?", a: "Using React.lazy() and Suspense to only load the code for the route the user is currently visiting, improving initial load speed.", type: "Scenario" },
        { level: "Senior", q: "Explain the 'Data Loader' feature in React Router 6.4+.", a: "It allows fetching route-specific data before the component even starts rendering, leading to faster user experiences.", type: "Conceptual" },
        { level: "Senior", q: "What is the benefit of the 'index' route?", a: "It defines the default child route to render within an Outlet when the parent path is matched exactly.", type: "Conceptual" },
        { level: "Senior", q: "How do you handle 'Breadcrumbs' dynamically?", a: "By using useLocation to parse the current path and mapping the segments to display a navigation trail.", type: "Scenario" },
        { level: "Senior", q: "Explain 'Actions' in 6.4 and how they handle mutations.", a: "Actions handle non-GET requests (POST/PUT/DELETE) and automatically re-validate Loaders after the mutation completes.", type: "Conceptual" },
        { level: "Senior", q: "What is 'Fetcher' and when to use it over navigate?", a: "Fetcher allows interacting with actions/loaders without changing the URL, ideal for small UI updates like 'adding to cart'.", type: "Scenario" },
        { level: "Senior", q: "Explain 'Deferred Data' and streaming.", a: "Using the 'defer' utility to return a promise from a loader, allowing the UI to show a fallback until the critical data arrives.", type: "Conceptual" },
        { level: "Senior", q: "How do you handle 'Race Conditions' in route loading?", a: "React Router handles this automatically by cancelling previous requests if a new navigation occurs before the first one finishes.", type: "Conceptual" },
        { level: "Senior", q: "Design a 'Multi-Step Wizard' using nested routes.", a: "A parent route for the wizard with an Outlet, where each step is a child route (/step1, /step2). State can be in context.", type: "Scenario" },
        { level: "Senior", q: "How would you implement 'Global Loading' indicators (non-Skeleton)?", a: "Use useNavigation().state to check if matching 'loading' and display a top-level progress bar.", type: "Scenario" },
        { level: "Senior", q: "Explain 'Error Boundaries' at the route level.", a: "Each route can have an 'errorElement' that catches errors only for that branch of the tree, keeping the rest of the UI intact.", type: "Scenario" },
        { level: "Senior", q: "How do you handle path matching priority in v6?", a: "V6 uses a ranking algorithm instead of 'first match', so the most specific route always wins regardless of order.", type: "Conceptual" },
        { level: "Senior", q: "Explain 'StaticRouter' for SEO and SSR.", a: "It is a stateless router that takes the current URL as a prop, intended for server-side environments where history doesn't exist.", type: "Conceptual" },
        { level: "Senior", q: "How to handle 'Custom History' with Router outside React?", a: "By using the <Router> component directly (not BrowserRouter) and passing a custom history object created with 'history' library.", type: "Scenario" },
        { level: "Junior", q: "What is 'useParams'?", a: "A hook that returns an object of key/value pairs of URL parameters from the current URL that were matched by the <Route path>.", type: "Conceptual" },
        { level: "Junior", q: "What is 'useNavigate'?", a: "A hook that returns a function that lets you navigate programmatically.", type: "Conceptual" },
        { level: "Mid", q: "Explain 'useSearchParams'.", a: "Used to read and modify the query string in the URL (e.g., ?search=term).", type: "Coding" },
        { level: "Mid", q: "What is '<Outlet />'?", a: "A component that should be used in parent route elements to render their child route elements.", type: "Conceptual" },
        { level: "Senior", q: "Explain 'Loader' and 'Action' in React Router 6.4+.", a: "Loaders fetch data before rendering; Actions handle mutations like POST/PUT during form submission.", type: "Conceptual" },
        { level: "Senior", q: "How do you implement 'Protected Routes'?", a: "By creating a wrapper component that checks for auth and either renders the <Outlet /> or redirects to login.", type: "Scenario" },
        { level: "Senior", q: "Explain 'Nested Routing'.", a: "Defining sub-routes within a parent path, allowing for layouts that persist while inner content changes.", type: "Conceptual" },
        { level: "Senior", q: "How do you handle 'Breadcrumbs'?", a: "By using useMatches or useLocation to match the current path segments to route titles.", type: "Scenario" },
        { level: "Junior", q: "What is 'NavLink'?", a: "A special version of Link that will add class attributes to the element when it matches the current URL.", type: "Conceptual" },
        { level: "Mid", q: "Explain 'Path Strategy' in v6.", a: "React Router v6 uses a ranking system for paths so the 'best' match is chosen regardless of order.", type: "Conceptual" }
      ]
